import logging
from flask import Flask, request, jsonify

app = Flask(__name__)

# Set up logging
logging.basicConfig(level=logging.DEBUG)
logger = logging.getLogger()

@app.route('/api', methods=['GET'])
def api():
    # Log the API request
    logger.info('API Request: %s %s', request.method, request.url)

    # Log the request headers and body data
    for header in request.headers:
        logger.debug('Header: %s = %s', header, request.headers[header])
    if request.data:
        logger.debug('Body Data: %s', request.data)

    # Log the user information for debugging
    logger.debug('User Information: %s', request.user_info)

    # Return a JSON response
    return jsonify({'message': 'Hello, World!'})

@app.errorhandler(Exception)
def handle_exception(e):
    # Log the error and return a JSON response
    logger.error('Error: %s', e)
    return jsonify({'message': 'An error occurred.'}), 500